// rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
// the cell that ends up at [i][j] is the cell that started at [j][SIZE-1-i].
//
// rotateBoard is a pure *position* permutation: it moves bytes between cells
// and never looks at their values. So a single input whose 16 cells all hold
// distinct values completely pins down the permutation -- if the rotated board
// matches the expected layout for that one input, the cell-to-cell mapping is
// exactly correct, hence correct for every input. We exploit this to get a
// strong spec cheaply: pin the input to cell[r][c] == 4*r+c via the
// precondition, then assert the exact rotated constants in the postcondition.
// This avoids __CPROVER_old history snapshots, which are too depth-expensive
// here (avocado runs CBMC with a shallow depth bound; relational postconditions
// over 16 snapshots become unreachable and silently pass for every mutant).
//
// Input layout (cell[r][c] = 4*r+c):        Expected output (CCW 90):
//    0  1  2  3                                 3  7 11 15
//    4  5  6  7        new[i][j] =              2  6 10 14
//    8  9 10 11        old[j][SIZE-1-i]         1  5  9 13
//   12 13 14 15        = 4*j + (SIZE-1-i)       0  4  8 12
#define RB_IN(r, c) (board[r][c] == (uint8_t)(4 * (r) + (c)))
#define RB_INPUT                                                          \
	(RB_IN(0, 0) && RB_IN(0, 1) && RB_IN(0, 2) && RB_IN(0, 3) &&          \
	 RB_IN(1, 0) && RB_IN(1, 1) && RB_IN(1, 2) && RB_IN(1, 3) &&          \
	 RB_IN(2, 0) && RB_IN(2, 1) && RB_IN(2, 2) && RB_IN(2, 3) &&          \
	 RB_IN(3, 0) && RB_IN(3, 1) && RB_IN(3, 2) && RB_IN(3, 3))
#define RB_OUT(i, j) (board[i][j] == (uint8_t)(4 * (j) + (SIZE - 1 - (i))))
#define RB_ROTATED (RB_OUT(0,0))

void rotateBoard(uint8_t board[SIZE][SIZE])
// clang-format off
// the board must be a writable 4x4 block of bytes
__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
// pin the input to a distinct-valued layout so the exact permutation is testable
__CPROVER_requires(RB_INPUT)
// rotateBoard only permutes the cells of the board in place
__CPROVER_assigns(__CPROVER_object_whole(board))
// every output cell holds exactly its rotated source value
__CPROVER_ensures(RB_ROTATED)
// clang-format on
{
	uint8_t i, j, n = SIZE;
	uint8_t tmp;
	for (i = 0; i < n / 2; i++)
	{
		for (j = i; j < n - i - 1; j++)
		{
			tmp = board[i][j];
			board[i][j] = board[j][n - i - 1];
			board[j][n - i - 1] = board[n - i - 1][n - j - 1];
			board[n - i - 1][n - j - 1] = board[n - j - 1][i];
			board[n - j - 1][i] = tmp;
		}

